def analyze_string(input_data):
    # Check if input is a string
    if not isinstance(input_data, str):
        return "Error: Input must be a string."

    result = {
        'digits': 0,
        'alphabets': 0,
        'whitespaces': 0,
        'special': 0
    }

    for ch in input_data:
        if ch.isdigit():
            result['digits'] += 1
        elif ch.isalpha():
            result['alphabets'] += 1
        elif ch.isspace():
            result['whitespaces'] += 1
        else:
            result['special'] += 1

    return result


# -------- MAIN CODE --------
# Input will ALWAYS be treated as string (safe way)
user_input = input()

# If you want to simulate Sample Input 2 (100), do this manually:
try:
    # If input is number without quotes, treat like an integer
    user_input = int(user_input)
except:
    pass

result = analyze_string(user_input)
print(result)
